import { appendFileSync, readFileSync, mkdirSync, existsSync } from "node:fs";
import path from "node:path";

const DATA = path.join(process.cwd(), "data", "orders.jsonl");

export function recordOrder(order) {
  mkdirSync(path.dirname(DATA), { recursive: true });
  // BUG: writes `orderId` but tests/readers expect `id`
  const row = { orderId: order.id, sku: order.sku, qty: order.qty, ts: Date.now() };
  appendFileSync(DATA, JSON.stringify(row) + "\n", "utf8");
}

export function listOrders() {
  if (!existsSync(DATA)) return [];
  return readFileSync(DATA, "utf8")
    .trim()
    .split("\n")
    .filter(Boolean)
    .map((line) => JSON.parse(line));
}

