import test from "node:test";
import assert from "node:assert/strict";
import { rmSync, existsSync } from "node:fs";
import { recordOrder, listOrders } from "../src/orders.js";

test("recordOrder writes id field", () => {
  if (existsSync("data")) rmSync("data", { recursive: true, force: true });
  recordOrder({ id: "o-1", sku: "X", qty: 1 });
  const rows = listOrders();
  assert.equal(rows.length, 1);
  assert.equal(rows[0].id, "o-1");
  assert.equal(rows[0].sku, "X");
});
